function handleGlobalEvents(store, queryClient) {
	const unlistenServerError = listen("server-error", () => {
		store.dispatch(addGenericErrorNotification());
	});
	const unlistenOrphanedPayees = listen("orphaned-payees", ({ orphanedIds, updatedPayeeIds }) => {
		store.dispatch(pushModal({ modal: {
			name: "merge-unused-payees",
			options: {
				payeeIds: orphanedIds,
				targetPayeeId: updatedPayeeIds[0]
			}
		} }));
	});
	const unlistenSchedulesOffline = listen("schedules-offline", () => {
		store.dispatch(pushModal({ modal: { name: "schedule-posts-offline-notification" } }));
	});
	const unlistenSync = listenForSyncEvent(store, queryClient);
	const unlistenUndo = listen("undo-event", (undoState) => {
		const { tables, undoTag } = undoState;
		const promises = [];
		if (tables.includes("categories") || tables.includes("category_groups") || tables.includes("category_mapping")) promises.push(queryClient.invalidateQueries({ queryKey: categoryQueries.lists() }));
		if (tables.includes("accounts") || tables.includes("payees") || tables.includes("payee_mapping")) queryClient.invalidateQueries({ queryKey: payeeQueries.lists() });
		if (tables.includes("accounts")) promises.push(queryClient.invalidateQueries({ queryKey: accountQueries.lists() }));
		const tagged = getTaggedState(undoTag);
		if (tagged) Promise.all(promises).then(() => {
			setUndoState("undoEvent", undoState);
			if (tagged.openModal) {
				const { modalStack } = store.getState().modals;
				if (modalStack.length === 0 || modalStack[modalStack.length - 1].name !== tagged.openModal.name) store.dispatch(replaceModal({ modal: tagged.openModal }));
			} else {
				store.dispatch(closeModal());
				if (window.location.href.replace(window.location.origin, "") !== tagged.url) {
					window.__navigate(tagged.url);
					return true;
				}
			}
		});
	});
	const unlistenFallbackWriteError = listen("fallback-write-error", () => {
		store.dispatch(addNotification({ notification: {
			type: "error",
			title: "Unable to save changes",
			sticky: true,
			message: "This browser only supports using the app in one tab at a time, and another tab has opened the app. No changes will be saved from this tab; please close it and continue working in the other one."
		} }));
	});
	const unlistenStartLoad = listen("start-load", () => {
		store.dispatch(closeBudgetUI());
		store.dispatch(setAppState({ loadingText: "" }));
	});
	const unlistenFinishLoad = listen("finish-load", () => {
		store.dispatch(closeModal());
		store.dispatch(setAppState({ loadingText: null }));
		store.dispatch(loadPrefs());
	});
	const unlistenStartImport = listen("start-import", () => {
		store.dispatch(closeBudgetUI());
	});
	const unlistenFinishImport = listen("finish-import", () => {
		store.dispatch(closeModal());
		store.dispatch(setAppState({ loadingText: null }));
		store.dispatch(loadPrefs());
	});
	const unlistenShowBudgets = listen("show-budgets", () => {
		store.dispatch(closeBudgetUI());
		store.dispatch(setAppState({ loadingText: null }));
	});
	const unlistenApiFetchRedirected = listen("api-fetch-redirected", () => {
		window.Actual.reload();
	});
	return () => {
		unlistenServerError();
		unlistenOrphanedPayees();
		unlistenSchedulesOffline();
		unlistenSync();
		unlistenUndo();
		unlistenFallbackWriteError();
		unlistenStartLoad();
		unlistenFinishLoad();
		unlistenStartImport();
		unlistenFinishImport();
		unlistenShowBudgets();
		unlistenApiFetchRedirected();
	};
}
