function _authorize(dispatch, { onSuccess, onClose }) {
	dispatch(pushModal({ modal: {
		name: "gocardless-external-msg",
		options: {
			onMoveExternal: async ({ institutionId }) => {
				const resp = await send("gocardless-create-web-token", {
					institutionId,
					accessValidForDays: 90
				});
				if ("error" in resp) return resp;
				const { link, requisitionId } = resp;
				window.Actual.openURLInBrowser(link);
				return send("gocardless-poll-web-token", { requisitionId });
			},
			onClose,
			onSuccess
		}
	} }));
}
async function authorizeBank(dispatch) {
	_authorize(dispatch, { onSuccess: async (data) => {
		dispatch(pushModal({ modal: {
			name: "select-linked-accounts",
			options: {
				externalAccounts: data.accounts,
				requisitionId: data.id,
				syncSource: "goCardless"
			}
		} }));
	} });
}
