		const openRequest = indexedDB.open("actual", 9);
		openRequest.onupgradeneeded = function(e) {
			const db = e.target.result;
			if (db.objectStoreNames.contains("filesystem")) db.deleteObjectStore("filesystem");
			if (db.objectStoreNames.contains("messages")) db.deleteObjectStore("messages");
			if (!db.objectStoreNames.contains("asyncStorage")) db.createObjectStore("asyncStorage");
			if (!db.objectStoreNames.contains("files")) db.createObjectStore("files", { keyPath: "filepath" });
		};
